import{_ as i,a,b as n}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as t,o,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Authentication এবং Login Device Management","description":"","frontmatter":{},"headers":[],"relativePath":"bn-BD/Safety/authentication-and-login-devices.md","filePath":"bn-BD/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),d={name:"bn-BD/Safety/authentication-and-login-devices.md"};function r(c,e,u,p,m,h){return o(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="authentication-এবং-login-device-management" tabindex="-1">Authentication এবং Login Device Management <a class="header-anchor" href="#authentication-এবং-login-device-management" aria-label="Permalink to &quot;Authentication এবং Login Device Management&quot;">​</a></h1><p><code>Authentication Management</code> এবং <code>Login Device Management</code> আপনার ImgBed admin panel, public upload entry এবং WebDAV access সুরক্ষিত রাখে।</p><p>এই পেজ থেকে access credentials সেট করা, signed-in devices দেখা এবং দরকার হলে পুরোনো sessions revoke করা যায়।</p><h2 id="কোথায়-configure-করবেন" tabindex="-1">কোথায় Configure করবেন <a class="header-anchor" href="#কোথায়-configure-করবেন" aria-label="Permalink to &quot;কোথায় Configure করবেন&quot;">​</a></h2><p>Admin panel খুলে যান:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings</span></span></code></pre></div><p>এই page-এ দুটি প্রধান area আছে:</p><ul><li>Authentication Management</li><li>Login Device Management</li></ul><p><img src="'+i+'" alt="Authentication management" loading="lazy"></p><h2 id="authentication-management-কী-করে" tabindex="-1">Authentication Management কী করে <a class="header-anchor" href="#authentication-management-কী-করে" aria-label="Permalink to &quot;Authentication Management কী করে&quot;">​</a></h2><p>Authentication Management access credentials সংরক্ষণ করে।</p><p>এর দুই ধরনের authentication আছে:</p><ul><li>User-side authentication</li><li>Admin-side authentication</li></ul><h2 id="user-side-authentication" tabindex="-1">User-Side Authentication <a class="header-anchor" href="#user-side-authentication" aria-label="Permalink to &quot;User-Side Authentication&quot;">​</a></h2><p>User-side authentication হলো upload password।</p><p>Upload password সেট করলে সাধারণ visitors-কে upload page ব্যবহার করার আগে password দিতে হবে। Public upload page সবার জন্য খোলা রাখতে না চাইলে এটি কাজে লাগে।</p><p><img src="'+a+'" alt="User login page" loading="lazy"></p><h3 id="upload-password-সেট-করা" tabindex="-1">Upload Password সেট করা <a class="header-anchor" href="#upload-password-সেট-করা" aria-label="Permalink to &quot;Upload Password সেট করা&quot;">​</a></h3><p>Upload password configured থাকলে:</p><ul><li>Visitors-কে upload page ব্যবহারের আগে password দিতে হবে।</li><li>Password accepted হওয়ার পরই upload করা যাবে।</li><li>User-side device sessions enabled থাকলে ImgBed সেই user-side device record করে।</li></ul><p>Upload password বদলালে পুরোনো user-side sessions invalid হয়ে যায়। Visitors-কে নতুন password আবার দিতে হবে।</p><h2 id="admin-side-authentication" tabindex="-1">Admin-Side Authentication <a class="header-anchor" href="#admin-side-authentication" aria-label="Permalink to &quot;Admin-Side Authentication&quot;">​</a></h2><p>Admin-side authentication admin username এবং password ব্যবহার করে।</p><p>এটি admin panel সুরক্ষিত রাখে। Production use-এর জন্য এটি সবসময় configure করা উচিত।</p><p><img src="'+n+'" alt="Admin login page" loading="lazy"></p><h3 id="admin-credentials-সেট-করা" tabindex="-1">Admin Credentials সেট করা <a class="header-anchor" href="#admin-credentials-সেট-করা" aria-label="Permalink to &quot;Admin Credentials সেট করা&quot;">​</a></h3><p>Admin username এবং password configured থাকলে:</p><ul><li>Admin panel খুলতে login করতে হবে।</li><li>Successful login একটি admin device record তৈরি করে।</li><li>Login Device Management-এ devices review, clean up বা force offline করা যায়।</li></ul><p>Admin username বা password বদলালে পুরোনো admin sessions invalid হয়ে যায়। আপনাকে আবার sign in করতে হবে।</p><h2 id="login-device-management-কী-করে" tabindex="-1">Login Device Management কী করে <a class="header-anchor" href="#login-device-management-কী-করে" aria-label="Permalink to &quot;Login Device Management কী করে&quot;">​</a></h2><p>Login Device Management signed-in devices দেখায়।</p><p>এটি দিয়ে দেখা যায়:</p><ul><li>কোন devices admin panel access করেছে।</li><li>কোন devices user-side upload page access করেছে।</li><li>কোন WebDAV clients connected হয়েছে।</li><li>কোনো device session এখনও valid আছে কি না।</li><li>পুরোনো devices force offline করা উচিত কি না।</li></ul><p>Page-এ তিনটি tabs আছে:</p><ul><li>Admin</li><li>User</li><li>WebDAV</li></ul><h2 id="global-cookie-security" tabindex="-1">Global Cookie Security <a class="header-anchor" href="#global-cookie-security" aria-label="Permalink to &quot;Global Cookie Security&quot;">​</a></h2><p>Login Device Management-এর উপরে global cookie behavior configure করা যায়।</p><h3 id="user-cookie-lifetime" tabindex="-1">User Cookie Lifetime <a class="header-anchor" href="#user-cookie-lifetime" aria-label="Permalink to &quot;User Cookie Lifetime&quot;">​</a></h3><p>User-side login কত দিন active থাকবে তা control করে।</p><p>যেমন, 14 days সেট করলে visitors সাধারণত 14 দিনের মধ্যে upload password আবার দিতে হবে না।</p><h3 id="admin-cookie-lifetime" tabindex="-1">Admin Cookie Lifetime <a class="header-anchor" href="#admin-cookie-lifetime" aria-label="Permalink to &quot;Admin Cookie Lifetime&quot;">​</a></h3><p>Admin login কত দিন active থাকবে তা control করে।</p><p>যেমন, 14 days সেট করলে administrators সাধারণত 14 দিনের মধ্যে আবার sign in করতে হবে না।</p><h3 id="secure-mode" tabindex="-1">Secure Mode <a class="header-anchor" href="#secure-mode" aria-label="Permalink to &quot;Secure Mode&quot;">​</a></h3><p>Secure mode enabled থাকলে browsers login cookies শুধু HTTPS দিয়ে পাঠায়।</p><p>Production HTTPS sites-এর জন্য এটি enable করুন। Local HTTP testing-এ enable করবেন না, না হলে &quot;login successful, কিন্তু refresh করলে logout&quot; ধরনের আচরণ দেখা যেতে পারে।</p><h2 id="admin-login-devices" tabindex="-1">Admin Login Devices <a class="header-anchor" href="#admin-login-devices" aria-label="Permalink to &quot;Admin Login Devices&quot;">​</a></h2><p>Admin tab admin panel-এ sign in করা devices দেখায়।</p><p>Device records তখনই দেখা যায় যখন admin credentials configured থাকে এবং admin panel login-এর মাধ্যমে access করা হয়।</p><p>প্রতিটি device card-এ দেখা যেতে পারে:</p><ul><li>Device এবং browser information</li><li>First login IP</li><li>Last active IP</li><li>Login time</li><li>Last active time</li><li>Expiration time</li><li>Current status</li></ul><p>অচেনা device দেখলে সেটি invalid করতে <code>Force Offline</code> ব্যবহার করুন।</p><h2 id="পুরোনো-devices-clean-up-করা" tabindex="-1">পুরোনো Devices Clean Up করা <a class="header-anchor" href="#পুরোনো-devices-clean-up-করা" aria-label="Permalink to &quot;পুরোনো Devices Clean Up করা&quot;">​</a></h2><p><code>Clean Up Old Devices</code> current tab-এর পুরোনো login records bulk-এ সরায়।</p><p>যখন মনে হয় পুরোনো sessions অন্য devices-এ এখনও active থাকতে পারে, তখন এটি ব্যবহার করুন।</p><h2 id="force-offline" tabindex="-1">Force Offline <a class="header-anchor" href="#force-offline" aria-label="Permalink to &quot;Force Offline&quot;">​</a></h2><p><code>Force Offline</code> একটি device session invalid করে।</p><p>Device force offline করার পর:</p><ul><li>Admin devices-কে আবার sign in করতে হবে।</li><li>User-side devices-কে upload password আবার দিতে হবে।</li><li>WebDAV clients-কে আবার authenticate করতে হবে।</li></ul><p>Expired বা invalid devices সরিয়েও দেওয়া যায়।</p><h2 id="current-device-থেকে-sign-out" tabindex="-1">Current Device থেকে Sign Out <a class="header-anchor" href="#current-device-থেকে-sign-out" aria-label="Permalink to &quot;Current Device থেকে Sign Out&quot;">​</a></h2><p>Current device card-এ <code>Current Device</code> mark থাকে।</p><p>Current device sign out করলে:</p><ul><li>Current admin session sign out হয়।</li><li>Current user-side session sign out হয়।</li></ul><p>ওই area ব্যবহার চালিয়ে যেতে আবার sign in করতে হবে।</p>',65)])])}const b=t(d,[["render",r]]);export{f as __pageData,b as default};
